// Dashboard.js
import React, { useEffect, useState } from "react";
import "./Dashboard.css";

import {
  getDashboard,
  getHistory,
  getGraphData,
  addTravel,
  addTicket,
  // uploadBill is used in Tools (we use fetch for file upload)
} from "./api/auth";

import { Bar, Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend
);

export default function Dashboard({ employee, onLogout }) {
  const empId = employee?.empId || localStorage.getItem("empId"); // fallback
  const [tab, setTab] = useState("dashboard"); // dashboard | addNew | tools | history
  const [summary, setSummary] = useState(null);
  const [history, setHistory] = useState({ travel: [], ticket: [], bills: [] });
  const [graph, setGraph] = useState([]);

  // forms
  const [travelForm, setTravelForm] = useState({
    travel_date: "",
    location_from: "",
    location_to: "",
    purpose: "",
    mode_of_travel: "",
    amount: "",
  });
  const [ticketForm, setTicketForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });

  useEffect(() => {
    if (empId) loadAll();
    // eslint-disable-next-line
  }, [empId]);

  const loadAll = async () => {
    try {
      const s = await getDashboard(empId);
      if (s.data.success) setSummary(s.data.dashboard);

      const h = await getHistory(empId);
      if (h.data.success) {
        // backend now returns travel, ticket and bills (see server.js update)
        const hist = h.data.history || {};
        setHistory({
          travel: hist.travel || [],
          ticket: hist.ticket || [],
          bills: hist.bills || [],
        });
      }

      const g = await getGraphData(empId);
      if (g.data.success) setGraph(g.data.graph);
    } catch (err) {
      console.error("Dashboard load error:", err);
    }
  };

  // add travel
  const submitTravel = async (e) => {
    e.preventDefault();
    try {
      const res = await addTravel({ empId, ...travelForm, amount: Number(travelForm.amount) });
      if (res.data.success) {
        alert("Travel added");
        setTravelForm({ travel_date: "", location_from: "", location_to: "", purpose: "", mode_of_travel: "", amount: "" });
        loadAll();
        setTab("history");
      } else {
        alert("Failed to add travel");
      }
    } catch (err) {
      alert("Server error");
    }
  };

  // add ticket
  const submitTicket = async (e) => {
    e.preventDefault();
    try {
      const res = await addTicket({ empId, ...ticketForm, amount: Number(ticketForm.amount) });
      if (res.data.success) {
        alert("Ticket added");
        setTicketForm({ ticket_date: "", purpose: "", assigned_to: "", amount: "" });
        loadAll();
        setTab("history");
      } else {
        alert("Failed to add ticket");
      }
    } catch (err) {
      alert("Server error");
    }
  };

  // small helpers for rendering
  const renderSummary = () => (
    summary ? (
      <div>
        <h3>Dashboard Summary</h3>
        <div className="summary-box">
          <p>Total Travel: ₹{summary.totalTravel}</p>
          <p>Total Ticket: ₹{summary.totalTicket}</p>
          <p>Total Bills: {summary.totalBills}</p>
        </div>
      </div>
    ) : <p>Loading summary...</p>
  );

  return (
    <div className="dash-wrapper">
      {/* Top tabs */}
      <div className="nav-tabs" style={{ marginBottom: 12 }}>
        <button onClick={() => setTab("dashboard")}>Dashboard</button>
        <button onClick={() => setTab("addNew")}>Add New</button>
        <button onClick={() => setTab("tools")}>Tools</button>
        <button onClick={() => setTab("history")}>History</button>
        {/* logout is in Settings only */}
      </div>

      <div className="content-box">
        {/* Dashboard tab */}
        {tab === "dashboard" && renderSummary()}

        {/* Add New: show sub-tabs for Travel / Ticket */}
        {tab === "addNew" && (
          <div>
            <h3>Add Travel</h3>
            <form onSubmit={submitTravel}>
              <input type="date" value={travelForm.travel_date} onChange={(e) => setTravelForm({ ...travelForm, travel_date: e.target.value })} />
              <input placeholder="From" value={travelForm.location_from} onChange={(e) => setTravelForm({ ...travelForm, location_from: e.target.value })} />
              <input placeholder="To" value={travelForm.location_to} onChange={(e) => setTravelForm({ ...travelForm, location_to: e.target.value })} />
              <input placeholder="Purpose" value={travelForm.purpose} onChange={(e) => setTravelForm({ ...travelForm, purpose: e.target.value })} />
              <input placeholder="Mode of Travel" value={travelForm.mode_of_travel} onChange={(e) => setTravelForm({ ...travelForm, mode_of_travel: e.target.value })} />
              <input placeholder="Amount" type="number" value={travelForm.amount} onChange={(e) => setTravelForm({ ...travelForm, amount: e.target.value })} />
              <button type="submit">Add Travel</button>
            </form>

            <hr style={{ margin: "20px 0" }} />

            <h3>Add Ticket</h3>
            <form onSubmit={submitTicket}>
              <input type="date" value={ticketForm.ticket_date} onChange={(e) => setTicketForm({ ...ticketForm, ticket_date: e.target.value })} />
              <input placeholder="Purpose" value={ticketForm.purpose} onChange={(e) => setTicketForm({ ...ticketForm, purpose: e.target.value })} />
              <input placeholder="Assigned To" value={ticketForm.assigned_to} onChange={(e) => setTicketForm({ ...ticketForm, assigned_to: e.target.value })} />
              <input placeholder="Amount" type="number" value={ticketForm.amount} onChange={(e) => setTicketForm({ ...ticketForm, amount: e.target.value })} />
              <button type="submit">Add Ticket</button>
            </form>
          </div>
        )}

        {/* Tools tab content is in Tools.jsx route; show quick link */}
        {tab === "tools" && (
          <div>
            <h3>Tools</h3>
            <p>Use the Tools page for Uploads, Graphs and Reports.</p>
            <div style={{ display: "flex", gap: 12 }}>
              <a className="home-btn" href="/tools">Open Tools</a>
            </div>
          </div>
        )}

        {/* History tab (includes Travel, Ticket, Bill History) */}
        {tab === "history" && (
          <div>
            <h3>History</h3>

            <h4>Travel</h4>
            {history.travel.length === 0 && <p>No travel history</p>}
            {history.travel.map((t) => (
              <div key={t.id}>
                {t.travel_date} — {t.location_from} → {t.location_to} — ₹{t.amount}
              </div>
            ))}

            <h4 style={{ marginTop: 16 }}>Ticket</h4>
            {history.ticket.length === 0 && <p>No ticket history</p>}
            {history.ticket.map((t) => (
              <div key={t.id}>
                {t.ticket_date} — {t.purpose} — ₹{t.amount}
              </div>
            ))}

            <h4 style={{ marginTop: 16 }}>Bills</h4>
            {history.bills.length === 0 && <p>No bills uploaded</p>}
            {history.bills.map((b) => (
              <div key={b.id}>
                {b.month_year} — {b.file_name} — <a href={`/uploads/${b.file_path}`} target="_blank" rel="noreferrer">Download</a>
              </div>
            ))}
          </div>
        )}

      </div>
    </div>
  );
}
